#include <stdio.h>
#include <windows.h>

void log_to_file(char* text) {
    FILE *file;
    file = fopen("clipboard.txt", "a");
    fprintf(file, "%s\n", text);
    fclose(file);
}

char* get_clipboard_text() {
    char* text;
    size_t text_size;

    if (!GetClipboardData(CF_TEXT)) {
        return NULL;
    }

    if (!GetClipboardFormatName(CF_TEXT, NULL, 0) || GetLastError() != ERROR_INSUFFICIENT_BUFFER) {
        CloseClipboard();
        return NULL;
    }

    text_size = GetClipboardFormatName(CF_TEXT, NULL, 0);

    text = malloc(text_size);

    if (text == NULL) {
        CloseClipboard();
        return NULL;
    }

    if (!GetClipboardFormatName(CF_TEXT, text, text_size) || GetLastError() != ERROR_SUCCESS) {
        free(text);
        CloseClipboard();
        return NULL;
    }

    return text;
}

int main(void)
{
    while (1) {
        char* text = get_clipboard_text();

        if (text != NULL && strcmp(text, "") != 0) {
            printf("[+] %s\n", text);
            log_to_file(text);
            free(text);
        }
        Sleep(500);
    }

    return 0;
}